export function checkCollisions(p, player, obstacles, portals, gameState) {
  // Check for obstacle collisions
  for (const obstacle of obstacles) {
    if (p.collideRectRect(
      player.x, player.y, player.width, player.height,
      obstacle.x, obstacle.y, obstacle.width, obstacle.height
    )) {
      // Special case for ground platform - don't die
      if (obstacle.type === 'block' && obstacle.y >= gameState.level.obstacles[0].y) {
        continue;
      }

      player.die();
      return true;
    }

    // Special check for spike collision (triangle)
    if (obstacle.type === 'spike') {
      // Simplified collision - treat spike as a smaller rectangle
      const spikeX = obstacle.x + obstacle.width * 0.25;
      const spikeY = obstacle.y + obstacle.height * 0.25;
      const spikeWidth = obstacle.width * 0.5;
      const spikeHeight = obstacle.height * 0.75;

      if (p.collideRectRect(
        player.x, player.y, player.width, player.height,
        spikeX, spikeY, spikeWidth, spikeHeight
      )) {
        player.die();
        return true;
      }
    }
  }

  // Check for portal collisions
  for (const portal of portals) {
    if (p.collideRectRect(
      player.x, player.y, player.width, player.height,
      portal.x, portal.y, portal.width, portal.height
    )) {
      player.changeMode(portal.targetMode);
    }
  }

  // Check if player reached the end
  if (player.x >= gameState.level.endX) {
    return 'win';
  }

  // Check if player fell below the level
  if (player.y > p.height + 100) {
    player.die();
    return true;
  }

  return false;
}
